import jsonimport requestsfrom common.handle_data import EnvDatafrom common.handle_config import confdef DingTalkSend(url):    testName = getattr(EnvData, "testName")    testAll = getattr(EnvData, "testAll")    testFail = getattr(EnvData, "testFail")    testPass = getattr(EnvData, "testPass")    # 钉钉推送    webhook = conf.get("env", "webhook")    headers = {"Content-Type": "application/json", "Charset": "UTF-8"}    data = {"msgtype": "text",            "text": {"content": "自动化测试项目" + ":掌上医馆接口自动化脚本执行完成。"                                "\n测试概述:" + "  " + str(testName) +                                "\n运行用例总数:" + "  " + str(testAll) +                                "\n通过用例数量:" + "  " + str(testPass) +                                "\n失败用例数量:" + "  " + str(testFail) +                                "\n报告地址:" + "  " + url},            "at": {"atMobiles": [], "isAtAll": False}            }    res = requests.post(webhook, data=json.dumps(data), headers=headers)    print(res.text)if __name__ == '__main__':    DingTalkSend(url="http://localhost:63342/Romens_apitest/reports/report.html?_ijt=5109f77qrism8dlrnmipgh3c42")